import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = new CSVFormat(',', '"', QuoteMode.ALL, '#', '\\', true, false, "\r\n", "NULL",
                new Object[]{"Header1", "Header2"}, new String[]{"Comment1", "Comment2"}, true, false, true, false,
                true);
    }

    @Test
    public void testWithHeaderComments() {
        // Given
        Object[] headerComments = {"Comment1", "Comment2", "Comment3"};

        // When
        CSVFormat newCsvFormat = csvFormat.withHeaderComments(headerComments);

        // Then
        assertEquals(3, newCsvFormat.getHeaderComments().length);
        assertEquals("Comment1", newCsvFormat.getHeaderComments()[0]);
        assertEquals("Comment2", newCsvFormat.getHeaderComments()[1]);
        assertEquals("Comment3", newCsvFormat.getHeaderComments()[2]);
    }
}
